{
  "data": [
    {
      "type": "osm",
      "pbfFileUrl": "docs/examples/data/niteroi.osm.pbf",
      "queryArea": { "geocodeArea": "Rio de Janeiro", "areas": ["Niter\u00f3i"] },
      "outputTableName": "table_osm",
      "autoLoadLayers": { "layers": ["surface", "parks", "water", "roads"], "dropOsmTable": true }
    },
    {
      "type": "join",
      "tableRootName": "table_osm_roads",
      "tableJoinName": "table_osm_surface",
      "near": { "distance": 50 },
      "groupBy": [{ "column": "osm_id", "aggregateFn": "count" }]
    }
  ],
  "compute": [{
    "dataRef": "table_osm_roads",
    "attributes": { "x": "lanes" },
    "outputColumnName": "lanes_norm",
    "wglsFunction": "if (x <= 0.0) { return 1.0; } if (x > 8.0) { return 8.0; } return x;"
  }],
  "map": {
    "layerRefs": [
      { "dataRef": "table_osm_surface" },
      { "dataRef": "table_osm_parks" },
      { "dataRef": "table_osm_water" },
      { "dataRef": "table_osm_roads", "isPick": true, "getFnv": "compute.lanes_norm", "getFnvType": "quantitative", "defaultFnv": 1 }
    ]
  },
  "plot": {
    "dataRef": "table_osm_roads",
    "mark": "bar",
    "axis": ["compute.lanes_norm", "@transform"],
    "title": "Niter\u00f3i road lane distribution",
    "transform": { "preset": "binning-1d", "options": { "bins": 8 } },
    "events": ["brushX"],
    "mapRef": "table_osm_roads"
  }
}
